const llm1Output = $input.first().json;
let flags;

try {
  const content = llm1Output.message?.content || llm1Output.choices?.[0]?.message?.content || '{}';
  flags = JSON.parse(content);
} catch (e) {
  flags = {};
}

const result = {
  ask_help: flags.ask_help || false,
  ask_report: flags.ask_report || false,
  ask_recommendation: flags.ask_recommendation || false,
  ask_prediction: flags.ask_prediction || false,
  ask_pdf: flags.ask_pdf || false,
  ask_chart: flags.ask_chart || false
};

const needsProcessing = result.ask_help || result.ask_report || result.ask_recommendation || result.ask_prediction;



const context = $('Extract Context').first().json;

return {
  json: {
    ...result,
    needsProcessing,
    user_message: context.message,
    context: {
      user_id: context.user_id,
      session_id: context.session_id,
      current_project: context.current_project,
      page_context: context.page_context,
      chat_history: (context.chat_history || []).slice(-3),
      language: flags.detected_language
    }
  }
};

