const llm3Output = $input.first().json;
let response;

try {
  const content = llm3Output.message?.content || llm3Output.choices?.[0]?.message?.content || '{}';
  response = JSON.parse(content);
} catch (e) {
  response = {
    message: "I encountered an error processing your request.",
    report: null
  };
}

if (response.report?.chart_data) {
  const validChartTypes = ['bar', 'line', 'pie', 'scatter', 'histogram', 'heatmap'];
  if (!validChartTypes.includes(response.report.chart_data.chart_plan)) {
    response.report.chart_data = null;
  }
  if (response.report.chart_data?.labels?.length !== response.report.chart_data?.values?.length) {
    response.report.chart_data = null;
  }
}

return {

  ...response,
  flags: {ask_chart:$('Aggregate Data').first().json.flags.ask_chart , ask_pdf:$('Aggregate Data').first().json.flags.ask_pdf  },
};
